from collections import deque

class Solution:
    def finalString(self, s):
        buf = deque()
        flipped = False
        for c in s:
            if c == 'i':
                flipped = not flipped
            elif flipped:
                buf.appendleft(c)
            else:
                buf.append(c)
        if flipped:
            buf.reverse()
        return ''.join(buf)

