var finalString = function(s) {
    const buf = [];
    let flipped = false;
    for (const c of s) {
        if (c === 'i') {
            flipped = !flipped;
        } else if (flipped) {
            buf.unshift(c);
        } else {
            buf.push(c);
        }
    }
    if (flipped) {
        buf.reverse();
    }
    return buf.join('');
};
